}

.btn-secondary:hover {
  background: var(--accent-primary);
  border-color: var(--accent-primary);
  color: #ffffff;
}

/* Text Effects */
.text-gradient {
  color: var(--accent-secondary);
}

.text-accent {
  color: var(--accent-primary);
}

.text-center {
  text-align: center;
}

/* Animations */
@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(10px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes fadeInUp {
  from {
